1	package ingestion
2	
3	import (
4		"context"
5		"encoding/json"
6		"fmt"
7	
8		"github.com/google/uuid"
9		"github.com/jackc/pgx/v5"
10		"github.com/jackc/pgx/v5/pgxpool"
11		"github.com/riverqueue/river"
12		"github.com/sentioxyz/changelogue/internal/queue"
13	)
14	
15	// PgStore implements ReleaseStore using PostgreSQL + River for the transactional outbox.
16	type PgStore struct {
17		pool  *pgxpool.Pool
18		river *river.Client[pgx.Tx]
19	}
20	
21	func NewPgStore(pool *pgxpool.Pool, riverClient *river.Client[pgx.Tx]) *PgStore {
22		return &PgStore{pool: pool, river: riverClient}
23	}
24	
25	// IngestRelease inserts a release and enqueues a notify job in a single transaction.
26	// Returns an error on unique constraint violation (caller treats as idempotent skip).
27	func (s *PgStore) IngestRelease(ctx context.Context, sourceID string, result *IngestionResult) error {
28		tx, err := s.pool.Begin(ctx)
29		if err != nil {
30			return fmt.Errorf("begin tx: %w", err)
31		}
32		defer tx.Rollback(ctx)
33	
34		// Build raw_data from Metadata + Changelog so nothing is lost.
35		raw := make(map[string]string)
36		for k, v := range result.Metadata {
37			raw[k] = v
38		}
39		if result.Changelog != "" {
40			raw["changelog"] = result.Changelog
41		}
42		rawData, err := json.Marshal(raw)
43		if err != nil {
44			return fmt.Errorf("marshal raw_data: %w", err)
45		}
46	
47		releaseID := uuid.New().String()
48		_, err = tx.Exec(ctx,
49			`INSERT INTO releases (id, source_id, version, raw_data, released_at) VALUES ($1, $2, $3, $4, $5)`,
50			releaseID, sourceID, result.RawVersion, rawData, result.Timestamp,
51		)
52		if err != nil {
53			return fmt.Errorf("insert release: %w", err)
54		}
55	
56		_, err = s.river.InsertTx(ctx, tx, queue.NotifyJobArgs{
57			ReleaseID: releaseID,
58			SourceID:  sourceID,
59		}, nil)
60		if err != nil {
61			return fmt.Errorf("enqueue job: %w", err)
62		}
63	
64		_, err = s.river.InsertTx(ctx, tx, queue.GateCheckJobArgs{
65			SourceID:  sourceID,
66			ReleaseID: releaseID,
67			Version:   result.RawVersion,
68		}, nil)
69		if err != nil {
70			return fmt.Errorf("enqueue gate check: %w", err)
71		}
72	
73		if err := tx.Commit(ctx); err != nil {
74			return fmt.Errorf("commit: %w", err)
75		}
76		return nil
77	}
78	
79	// ListEnabledSources implements SourceLister.
80	func (s *PgStore) ListEnabledSources(ctx context.Context) ([]EnabledSource, error) {
81		rows, err := s.pool.Query(ctx,
82			`SELECT id, provider, repository, poll_interval_seconds, last_polled_at
83			 FROM sources WHERE enabled = true`)
84		if err != nil {
85			return nil, fmt.Errorf("query enabled sources: %w", err)
86		}
87		defer rows.Close()
88	
89		var sources []EnabledSource
90		for rows.Next() {
91			var e EnabledSource
92			if err := rows.Scan(&e.ID, &e.Provider, &e.Repository, &e.PollIntervalSeconds, &e.LastPolledAt); err != nil {
93				return nil, fmt.Errorf("scan source row: %w", err)
94			}
95			sources = append(sources, e)
96		}
97		return sources, rows.Err()
98	}
99	
100	// UpdateSourcePollStatus implements PollStatusUpdater.
101	func (s *PgStore) UpdateSourcePollStatus(ctx context.Context, id string, pollErr error) error {
102		var lastError *string
103		if pollErr != nil {
104			s := pollErr.Error()
105			lastError = &s
106		}
107		_, err := s.pool.Exec(ctx,
108			`UPDATE sources SET last_polled_at = NOW(), last_error = $1 WHERE id = $2`,
109			lastError, id)
110		return err
111	}
